## Code Example
```javascript
const AWS = require('aws-sdk');
const ssm = new AWS.SSM();
const s3 = new AWS.S3();
const sns = new AWS.SNS();

exports.handler = async (event) => {
  try {
    const params = {
      DocumentName: 'SAP-HANA-Backup-Verify',
      InstanceIds: [process.env.HANA_INSTANCE_ID],
      Parameters: {
        'backupPath': [event.backupPath]
      }
    };

    const command = await ssm.sendCommand(params).promise();

    // Wait for command completion and get results
    const result = await ssm.waitFor('commandExecuted', {
      CommandId: command.Command.CommandId,
      InstanceId: process.env.HANA_INSTANCE_ID
    }).promise();

    const report = {
      timestamp: new Date().toISOString(),
      backupPath: event.backupPath,
      status: result.Status,
      output: result.StandardOutputContent
    };

    await s3.putObject({
      Bucket: process.env.REPORT_BUCKET,
      Key: `backup-reports/${report.timestamp}.json`,
      Body: JSON.stringify(report, null, 2)
    }).promise();

    if (result.Status !== 'Success') {
      await sns.publish({
        TopicArn: process.env.ALERT_TOPIC,
        Subject: 'SAP HANA Backup Verification Failed',
        Message: JSON.stringify(report)
      }).promise();
    }

    return report;
  } catch (error) {
    console.error('Backup verification failed:', error);
    throw error;
  }
};
```

